def binary_search(arr, target):
    left, right = 0, len(arr) - 1  # Right boundary should be the index of the last element
    while left <= right:
        mid = (left + right) // 2
        if arr[mid] == target:
            return mid
        elif arr[mid] < target:
            # Target is in the right half
            left = mid + 1  # Move left past mid
        else:
            # Target is in the left half
            right = mid - 1 # Move right before mid
    return -1

